import React, { useContext, useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import axios from "axios";
import { UserContext } from "../context/UserContext";

export const ItemsForm = () => {
  const { id } = useParams();
  const [category, setCategory] = useState("upper");
  const [gender,setGender] = useState('male');
  const navigate = useNavigate();
  //   const [addedPhotos, setAddedPhotos] = useState([]);
  const [updateItem, setUpdateItem] = useState({});
  const { user } = useContext(UserContext);
  const [items, setItems] = useState({
    icategory: "upper",
    iname: "",
    imrp: "",
    isize: "",
    imaterial: "",
    icondition: "",
    prop1: "",
    prop2: "",
    prop3: "",
    prop4: "",
    prop5: "",
    photos: [],
    gender:"male",
    itype:""
  });

  useEffect(() => {
    const fetchData = async () => {
      if (!id) {
        return;
      }
      try {
        axios.defaults.headers.common.Authorization = `Bearer ${user.token}`;
        const response = await axios.get(`/items/getsingleitem/${id}`);
        const { _id, owner, createdAt, updatedAt, ...itemsData } =
          response.data;
        setItems({
          ...itemsData,
        });
        console.log(response.data);
      } catch (error) {
        console.log(error);
      }
    };

    fetchData();
  }, [id, user?.token]);

  const handleChange = (e) => {
    setItems({ ...items, [e.target.name]: e.target.value });
  };
  const handleCategory = (e) => {
    setCategory(e.target.value);
    setItems({ ...items, icategory: e.target.value });
  };
  const handleGender = (e) => {
    setGender(e.target.value);
    setItems({ ...items, gender: e.target.value });
  };

  const uploadPhoto = (e) => {
    const files = e.target.files;
    const data = new FormData();
    for (let i = 0; i < files.length; i++) {
      data.append("photos", files[i]);
    }
    axios
      .post("/uploads", data, {
        headers: { "Content-type": "multipart/form-data" },
      })
      .then((response) => {
        const { data: filenames } = response;
        console.log(filenames);
        setItems((prevItems) => ({
          ...prevItems,
          photos: [...prevItems.photos, ...filenames],
        }));
      });
  };

  const deletePhoto = (filename) => {
    setItems((prevItems) => ({
      ...prevItems,
      photos: prevItems.photos.filter((item) => item !== filename),
    }));
  };

  const starPhoto =(e,filename)=>{
    e.preventDefault()
    setItems((prevItems)=>({
      ...prevItems,
      photos:[filename ,...prevItems.photos.filter((item) => item !== filename)]
    }))
  }

  const handleSubmit = async (e) => {
    e.preventDefault();
    axios.defaults.headers.common.Authorization = `Bearer ${user.token}`;
    if (id) {
      try {
        await axios.patch(`/items/update/${id}`, items);
      } catch (error) {
        console.log(error);
      }
    } else {
      try {
        await axios.post("/items/add", items);
      } catch (error) {
        console.log(error);
      }
    }

    setItems({
      icategory: "upper",
      iname: "",
      imrp: "",
      isize: "",
      imaterial: "",
      icondition: "",
      prop1: "",
      prop2: "",
      prop3: "",
      prop4: "",
      prop5: "",
      photos: [],
      gender:"",
      itype:""
    });
    navigate("/account/items");
  };
  return (
    <div>
      <h1 className="flex justify-center w-full mt-8 text-2xl font-bold mb-4">Create Your Listing</h1>
      <div className="m-10 ml-20">
  
      <div className=" flex items-center gap-10">

        <div>
        <label htmlFor="icategory">Item Category : </label>
        <select name="icategory" id="icategory" onChange={handleCategory} className="p-2 cursor-pointer">
          <option value="upper" className="p-4">Upper Garment</option>
          <option value="lower">Lower Garment</option>
        </select>
        </div>

        <div>
        <label htmlFor="iname">Gender : </label>
            <select
            name="gender"
            id="gender"
            onChange={handleGender}
            value={items.gender}
            >
            <option value="null">Select Gender</option>
            <option value="male">Male</option>
            <option value="female">Female</option>
          </select>
              </div>

      </div>

      <div>

        <form onSubmit={handleSubmit}>
        <label htmlFor="isize">Item Type : </label>
          <select
            name="itype"
            id="itype"
            onChange={handleChange}
            value={items.itype}
          >
          {
            gender==="male" && category ==="upper" && (
              <>
             <option value="tshirt">T-Shirts</option>
            <option value="shirt">Shirts</option>
            <option value="sweathsirt">Sweatshirt</option>
            <option value="jacket">Jacket</option>
              </>
            )     }

            {
              (gender==="male" || gender==="female") && category ==="lower" && (
                <>
               <option value="trousers">Trousers</option>
              <option value="jeans">Jeans</option>
              <option value="shorts">Shorts</option>
                </>
              )  
            }
                        {
              gender==="female" && category ==="upper" && (
                <>
                  <option value="tops">Tops</option>
              <option value="dresses">Dresses</option>
              <option value="blouses">Blouses</option>
                </>
              )  
            }
          
          </select>
          <br />

          <label htmlFor="iname">Item Name : </label>
          <input
            type="text"
            name="iname"
            id="iname"
            onChange={handleChange}
            value={items.iname}
          /><br/>
            
          <label htmlFor="imrp">MRP : </label>
          <input
            type="text"
            name="imrp"
            id="imrp"
            onChange={handleChange}
            value={items.imrp}
          />
          <br />
          <label htmlFor="isize">Item Size : </label>
          <select
            name="isize"
            id="isize"
            onChange={handleChange}
            value={items.isize}
          >
            <option value="null">Select Size</option>
            <option value="large">Large</option>
            <option value="medium">Medium</option>
            <option value="small">Small</option>
            <option value="xl">XL</option>
            <option value="xxl">XXL</option>
          </select>
          <br />
          <label htmlFor="imaterial">Item Material : </label>
          <select
            name="imaterial"
            id="imaterial"
            onChange={handleChange}
            value={items.imaterial}
          >
            <option value="null">Select Material</option>
            <option value="cotton">Cotton</option>
            <option value="silk">Silk</option>
            <option value="nylon">Nylon</option>
            <option value="other">Other</option>
          </select>
          <br />
          <label htmlFor="icondition">Item Condition : </label>
          <select
            name="icondition"
            id="icondition"
            onChange={handleChange}
            value={items.icondition}
          >
            <option value="null">Select Condition</option>
            <option value="brandnew">Brand New</option>
            <option value="yearold">A Year Old</option>
            <option value="colorissue">Color Issues </option>
          </select>
          <br />
          <h2>Photos</h2>
          <div className="mt-2 grid grid-cols-3 gap-6 md:grid-cols-4 lg:grid-cols-6 ">
            {items.photos.length > 0 &&
              items.photos.map((link) => (
                <div className="h-32 flex relative" key={link}>
                  <img
                    className="rounded-2xl w-full object-cover"
                    alt="img not found"
                    src={"http://localhost:5000/" + link}
                  />
                  <button
                    onClick={() => deletePhoto(link)}
                    className="absolute bottom-1 right-1 text-white bg-black py-1 px-3 rounded-2xl bg-opacity-50"
                  >
                    <svg
                      xmlns="http://www.w3.org/2000/svg"
                      fill="none"
                      viewBox="0 0 24 24"
                      strokeWidth={1.5}
                      stroke="currentColor"
                      className="w-6 h-6"
                    >
                      <path
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        d="m14.74 9-.346 9m-4.788 0L9.26 9m9.968-3.21c.342.052.682.107 1.022.166m-1.022-.165L18.16 19.673a2.25 2.25 0 0 1-2.244 2.077H8.084a2.25 2.25 0 0 1-2.244-2.077L4.772 5.79m14.456 0a48.108 48.108 0 0 0-3.478-.397m-12 .562c.34-.059.68-.114 1.022-.165m0 0a48.11 48.11 0 0 1 3.478-.397m7.5 0v-.916c0-1.18-.91-2.164-2.09-2.201a51.964 51.964 0 0 0-3.32 0c-1.18.037-2.09 1.022-2.09 2.201v.916m7.5 0a48.667 48.667 0 0 0-7.5 0"
                      />
                    </svg>
                  </button>
                  <button
                    onClick={(e) => starPhoto( e,link)}
                    className="absolute bottom-1 left-1 text-white bg-black py-1 px-3 rounded-2xl bg-opacity-50"
                  >
                    {items.photos[0] === link && (
                      <svg
                        xmlns="http://www.w3.org/2000/svg"
                        viewBox="0 0 24 24"
                        fill="currentColor"
                        className="w-6 h-6"
                      >
                        <path
                          fillRule="evenodd"
                          d="M10.788 3.21c.448-1.077 1.976-1.077 2.424 0l2.082 5.006 5.404.434c1.164.093 1.636 1.545.749 2.305l-4.117 3.527 1.257 5.273c.271 1.136-.964 2.033-1.96 1.425L12 18.354 7.373 21.18c-.996.608-2.231-.29-1.96-1.425l1.257-5.273-4.117-3.527c-.887-.76-.415-2.212.749-2.305l5.404-.434 2.082-5.005Z"
                          clipRule="evenodd"
                        />
                      </svg>
                    )}
                    {items.photos[0] !== link && (
                      <svg
                        xmlns="http://www.w3.org/2000/svg"
                        fill="none"
                        viewBox="0 0 24 24"
                        strokeWidth={1.5}
                        stroke="currentColor"
                        className="w-6 h-6"
                      >
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          d="M11.48 3.499a.562.562 0 0 1 1.04 0l2.125 5.111a.563.563 0 0 0 .475.345l5.518.442c.499.04.701.663.321.988l-4.204 3.602a.563.563 0 0 0-.182.557l1.285 5.385a.562.562 0 0 1-.84.61l-4.725-2.885a.562.562 0 0 0-.586 0L6.982 20.54a.562.562 0 0 1-.84-.61l1.285-5.386a.562.562 0 0 0-.182-.557l-4.204-3.602a.562.562 0 0 1 .321-.988l5.518-.442a.563.563 0 0 0 .475-.345L11.48 3.5Z"
                        />
                      </svg>
                    )}
                  </button>
                </div>
              ))}

            <label className="h-32 cursor-pointer border bg-transparent rounded-2xl p-8 text-2xl text-gray-500">
              +
              <input
                type="file"
                multiple
                name="ifile"
                id="ifile"
                className="hidden"
                onChange={uploadPhoto}
              />
            </label>
          </div>
          <h3>Measurements</h3>
          <br />
          <label htmlFor="prop1">
            {category === "upper" ? "Shoulder : " : "Waist  : "}{" "}
          </label>
          <input
            type="text"
            name="prop1"
            id="prop1"
            onChange={handleChange}
            value={items.prop1}
          />
          <br />
          <label htmlFor="prop2">
            {category === "upper" ? "Sleeve Length : " : "Hip  : "}
          </label>
          <input
            type="text"
            name="prop2"
            id="prop2"
            onChange={handleChange}
            value={items.prop2}
          />
          <br />
          <label htmlFor="prop3">
            {category === "upper" ? "Chest : " : "Rise  : "}{" "}
          </label>
          <input
            type="text"
            name="prop3"
            id="prop3"
            onChange={handleChange}
            value={items.prop3}
          />
          <br />
          <label htmlFor="prop4">
            {category === "upper" ? "Waist : " : "Length  : "}
          </label>
          <input
            type="text"
            name="prop4"
            id="prop4"
            onChange={handleChange}
            value={items.prop4}
          />
          <br />
          <label htmlFor="prop5">
            {category === "upper" ? "Length : " : "Thigh Round  : "}{" "}
          </label>
          <input
            type="text"
            name="prop5"
            id="prop5"
            onChange={handleChange}
            value={items.prop5}
          />
          <br />
          <br />
          <input type="submit" name="submit" id="submit" />
        </form>
      </div>
      </div>
    </div>
  );
};
